public protocol PtyOutputSink: AnyObject, Sendable {
    
    func onOutput(id: UInt32, bytes: Data) 
    
    func onExit(id: UInt32, status: Int32?) 
    
    func onMetadata(id: UInt32, cwd: String?, process: String?) 
    
}


// Put the implementation in a struct so we don't pollute the top-level namespace
fileprivate struct UniffiCallbackInterfacePtyOutputSink {

    // Create the VTable using a series of closures.
    // Swift automatically converts these into C callback functions.
    //
    // Store the vtable directly.
    static let vtable: UniffiVTableCallbackInterfacePtyOutputSink = UniffiVTableCallbackInterfacePtyOutputSink(
        uniffiFree: { (uniffiHandle: UInt64) -> () in
            do {
                try FfiConverterCallbackInterfacePtyOutputSink.handleMap.remove(handle: uniffiHandle)
            } catch {
                print("Uniffi callback interface PtyOutputSink: handle missing in uniffiFree")
            }
        },
        uniffiClone: { (uniffiHandle: UInt64) -> UInt64 in
            do {
                return try FfiConverterCallbackInterfacePtyOutputSink.handleMap.clone(handle: uniffiHandle)
            } catch {
                fatalError("Uniffi callback interface PtyOutputSink: handle missing in uniffiClone")
            }
        },
        onOutput: { (
            uniffiHandle: UInt64,
            id: UInt32,
            bytes: RustBuffer,
            uniffiOutReturn: UnsafeMutableRawPointer,
            uniffiCallStatus: UnsafeMutablePointer<RustCallStatus>
        ) in
            let makeCall = {
                () throws -> () in
                guard let uniffiObj = try? FfiConverterCallbackInterfacePtyOutputSink.handleMap.get(handle: uniffiHandle) else {
                    throw UniffiInternalError.unexpectedStaleHandle
                }
                return uniffiObj.onOutput(
                     id: try FfiConverterUInt32.lift(id),
                     bytes: try FfiConverterData.lift(bytes)
                )
            }

            
            let writeReturn = { () }
            uniffiTraitInterfaceCall(
                callStatus: uniffiCallStatus,
                makeCall: makeCall,
                writeReturn: writeReturn
            )
        },
        onExit: { (
            uniffiHandle: UInt64,
            id: UInt32,
            status: RustBuffer,
            uniffiOutReturn: UnsafeMutableRawPointer,
            uniffiCallStatus: UnsafeMutablePointer<RustCallStatus>
        ) in
            let makeCall = {
                () throws -> () in
                guard let uniffiObj = try? FfiConverterCallbackInterfacePtyOutputSink.handleMap.get(handle: uniffiHandle) else {
                    throw UniffiInternalError.unexpectedStaleHandle
                }
                return uniffiObj.onExit(
                     id: try FfiConverterUInt32.lift(id),
                     status: try FfiConverterOptionInt32.lift(status)
                )
            }

            
            let writeReturn = { () }
            uniffiTraitInterfaceCall(
                callStatus: uniffiCallStatus,
                makeCall: makeCall,
                writeReturn: writeReturn
            )
        },
        onMetadata: { (
            uniffiHandle: UInt64,
            id: UInt32,
            cwd: RustBuffer,
            process: RustBuffer,
            uniffiOutReturn: UnsafeMutableRawPointer,
            uniffiCallStatus: UnsafeMutablePointer<RustCallStatus>
        ) in
            let makeCall = {
                () throws -> () in
                guard let uniffiObj = try? FfiConverterCallbackInterfacePtyOutputSink.handleMap.get(handle: uniffiHandle) else {
                    throw UniffiInternalError.unexpectedStaleHandle
                }
                return uniffiObj.onMetadata(
                     id: try FfiConverterUInt32.lift(id),
                     cwd: try FfiConverterOptionString.lift(cwd),
                     process: try FfiConverterOptionString.lift(process)
                )
            }

            
            let writeReturn = { () }
            uniffiTraitInterfaceCall(
                callStatus: uniffiCallStatus,
                makeCall: makeCall,
                writeReturn: writeReturn
            )
        }
    )

    // Rust stores this pointer for future callback invocations, so it must live
    // for the process lifetime (not just for the init function call).
    static let vtablePtr: UnsafePointer<UniffiVTableCallbackInterfacePtyOutputSink> = {
        let ptr = UnsafeMutablePointer<UniffiVTableCallbackInterfacePtyOutputSink>.allocate(capacity: 1)
        ptr.initialize(to: vtable)
        return UnsafePointer(ptr)
    }()
}

private func uniffiCallbackInitPtyOutputSink() {
    uniffi_edex_ffi_fn_init_callback_vtable_ptyoutputsink(UniffiCallbackInterfacePtyOutputSink.vtablePtr)
}

